const row = $input.first().json;

const lastId = Number(row.last_id ?? 0);
const refreshIds = Array.isArray(row.refresh_ids) ? row.refresh_ids.map(Number).filter(Number.isFinite) : [];

return [{
  json: {
    lastId,
    refreshIds,
    maxBytes: 5 * 1024 * 1024,
    refreshLimit: 200,
    newLimit: 200,
  }
}];

const ids = $input.all()
  .map(i => Number(i.json.id))
  .filter(Number.isFinite);

if (!ids.length) return [];

return [{ json: { executionIds: ids, maxBytes: 5 * 1024 * 1024 } }];

const ids = $json.executionIds || [];
const maxBytes = $json.maxBytes ?? 5 * 1024 * 1024;

const chunkSize = 20;
const out = [];

for (let i = 0; i < ids.length; i += chunkSize) {
  out.push({ json: { executionIds: ids.slice(i, i + chunkSize), maxBytes } });
}

return out;

const TIMEZONE = "UTC";
const INSTANCE_ID = $('Set Instance Context').first().json.INSTANCE_ID;
function isIndexString(s) {
  return typeof s === "string" && /^\d+$/.test(s);
}

function resolve(val, dict) {
  if (val === null || val === undefined) return null;
  if (isIndexString(val)) {
    const idx = Number(val);
    return dict[idx] ?? val;
  }
  return val;
}

function deepResolve(x, dict) {
  if (Array.isArray(x)) return x.map(v => deepResolve(v, dict));
  if (x && typeof x === "object") {
    const o = {};
    for (const [k, v] of Object.entries(x)) {
      o[k] = deepResolve(resolve(v, dict), dict);
    }
    return o;
  }
  return resolve(x, dict);
}

function formatDateTime(dt) {
  if (!dt) return null;
  const d = new Date(dt);
  if (isNaN(d.getTime())) return null;
  return d.toISOString().replace("T", " ").replace("Z", "");
}

function countItemsOutFromRunResolved(runResolved) {
  const main = runResolved?.data?.main || [];
  return main.reduce((sum, outputArr) => sum + (outputArr?.length || 0), 0);
}

function buildNodeTypeMap(row, dict) {

  try {
    const wfNodes =
      typeof row.workflowNodes === "string"
        ? JSON.parse(row.workflowNodes)
        : row.workflowNodes;

    if (Array.isArray(wfNodes)) {
      const map = {};
      for (const n of wfNodes) {
        if (n?.name) map[n.name] = n.type || null;
      }
      if (Object.keys(map).length) return map;
    }
  } catch (_) {}

  for (let i = 0; i < dict.length; i++) {
    const entry = dict[i];
    if (!entry || typeof entry !== "object" || Array.isArray(entry)) continue;

    const resolved = deepResolve(entry, dict);
    const nodes = resolved?.nodes;

    if (Array.isArray(nodes) && nodes.some(n => n?.name && n?.type)) {
      const map = {};
      for (const n of nodes) {
        if (n?.name) map[n.name] = n.type || null;
      }
      if (Object.keys(map).length) return map;
    }
  }

  return {};
}

const out = [];

for (const item of $input.all()) {
  const row = item.json || {};

  let dict;
  try {
    dict = JSON.parse(row.data);
  } catch (e) {
    out.push({
      json: {
        error: "حقل data ليس JSON صالح",
        executionId: row.executionId ?? null,
        details: e.message,
      }
    });
    continue;
  }

  const resultData = deepResolve(dict[2] || {}, dict);
  const runData = resultData?.runData || {};
  const lastNodeExecuted = resultData?.lastNodeExecuted ?? null;
  const nodeTypeByName = buildNodeTypeMap(row, dict);
  const startedAtIso = row.startedAt ?? null;
  const stoppedAtIso = row.stoppedAt ?? null;
  const durationMs =
    startedAtIso && stoppedAtIso
      ? (new Date(stoppedAtIso).getTime() - new Date(startedAtIso).getTime())
      : null;

  out.push({
    json: {
      rowType: "execution",
      instanceId: INSTANCE_ID,
      executionId: row.executionId != null ? String(row.executionId) : null,
      workflowId: row.workflowId != null ? String(row.workflowId) : null,

      status: row.status ?? null,
      finished: row.finished ?? null,
      mode: row.mode ?? null,

      startedAt: startedAtIso,
      stoppedAt: stoppedAtIso,
      startedAtFmt: formatDateTime(startedAtIso),
      stoppedAtFmt: formatDateTime(stoppedAtIso),
      durationMs,

      waitTill: row.waitTill ?? null,
      retryOf: row.retryOf ?? null,
      retrySuccessId: row.retrySuccessId ?? null,

      lastNodeExecuted: resolve(lastNodeExecuted, dict),
      nodeNamesExecuted: Object.keys(runData),
      nodesCount: Object.keys(runData).length,

      timeFormatTz: TIMEZONE,
    }
  });

  for (const [nodeName, runs] of Object.entries(runData)) {
    const runsArr = Array.isArray(runs) ? runs : [];
    const runsResolved = runsArr.map(r => deepResolve(r, dict));
    const itemsOutPerRun = runsResolved.map(countItemsOutFromRunResolved);
    const itemsOutTotalAllRuns = itemsOutPerRun.reduce((a, b) => a + b, 0);

    runsResolved.forEach((runResolved, runIndex) => {
      out.push({
        json: {
          rowType: "execution_node",
          instanceId: INSTANCE_ID,
          executionId: row.executionId != null ? String(row.executionId) : null,
          workflowId: row.workflowId != null ? String(row.workflowId) : null,

          nodeName,
          nodeType: nodeTypeByName[nodeName] || null,

          runIndex,
          runsCount: runsResolved.length,
          isLastRun: runIndex === runsResolved.length - 1,
          executionStatus: runResolved?.executionStatus ?? null,
          executionTimeMs: runResolved?.executionTime ?? null,

          startTimeMs: runResolved?.startTime ?? null,
          startTimeIso: runResolved?.startTime != null ? new Date(runResolved.startTime).toISOString() : null,
          startTimeFmt: runResolved?.startTime != null ? formatDateTime(runResolved.startTime) : null,

          itemsOutCount: itemsOutPerRun[runIndex] ?? 0,
          itemsOutTotalAllRuns,

          lastNodeExecuted: resolve(lastNodeExecuted, dict),
          timeFormatTz: TIMEZONE,
        }
      });
    });
  }
}

return out;

const INSTANCE_ID = $('Set Instance Context').first().json.INSTANCE_ID;

function durationMs(startedAt, stoppedAt) {
  if (!startedAt || !stoppedAt) return null;
  const s = new Date(startedAt).getTime();
  const t = new Date(stoppedAt).getTime();
  if (!Number.isFinite(s) || !Number.isFinite(t)) return null;
  return Math.max(0, t - s);
}

return $input.all().map(item => {
  const r = item.json;

  return {
    json: {
      rowType: "execution",
      instanceId: INSTANCE_ID,
      executionId: r.executionId != null ? String(r.executionId) : null,
      workflowId: r.workflowId != null ? String(r.workflowId) : null,

      status: r.status ?? null,
      finished: r.finished ?? null,
      mode: r.mode ?? null,

      startedAt: r.startedAt ?? null,
      stoppedAt: r.stoppedAt ?? null,
      durationMs: durationMs(r.startedAt, r.stoppedAt),

      waitTill: r.waitTill ?? null,
      retryOf: r.retryOf ?? null,
      retrySuccessId: r.retrySuccessId ?? null,
      lastNodeExecuted: null,
      nodeNamesExecuted: [],
      nodesCount: 0,
    }
  };
});

const INSTANCE_ID =$('Set Instance Context').first().json.INSTANCE_ID
function asArray(v) {
  if (Array.isArray(v)) return v;
  if (v == null) return [];
  if (typeof v === 'string') {
    try {
      const parsed = JSON.parse(v);
      return Array.isArray(parsed) ? parsed : [];
    } catch {
      return [];
    }
  }
  return [];
}

function uniqueSorted(arr) {
  const out = Array.from(new Set(arr.filter(x => x != null && String(x).trim() !== '').map(String)));
  out.sort((a, b) => a.localeCompare(b));
  return out;
}

const timeFormatTz = 'UTC';


const items = $input.all();

return items.map((item) => {
  const j = item.json || {};

  const tags = uniqueSorted(asArray(j.tags));
  const nodeTypesDistinct = uniqueSorted(asArray(j.nodeTypesDistinct));
  const nodeNamesDistinct = uniqueSorted(asArray(j.nodeNamesDistinct));


  const nodesCount = Number.isFinite(Number(j.nodesCount)) ? Number(j.nodesCount) : 0;

  return {
    json: {
      INSTANCE_ID,
      rowType: "workflow_index",
      instanceId: j.instanceId ?? "prod",
      workflowId: String(j.workflowId ?? ""),
      name: j.name ?? null,
      active: !!j.active,
      isArchived: !!j.isArchived,
      createdAt: j.createdAt ?? null,
      updatedAt: j.updatedAt ?? null,
      tags,
      nodesCount,
      nodeTypesDistinct,
      nodeNamesDistinct,
      timeFormatTz,
    }
  };
});
